 17	export type OverviewNamespaceAction = {
 18	  action?: (namespace: string) => void;
 19	  children?: OverviewNamespaceAction[];
 20	  isDisabled?: boolean;
 21	  isExternal?: boolean;
 22	  isGroup: boolean;
 23	  isSeparator: boolean;
 24	  title?: string;
 25	};
 26	
 27	type Props = {
 28	  actions: OverviewNamespaceAction[];
 29	  namespace: string;
 30	};
 31	
 32	export const OverviewNamespaceActions: React.FC<Props> = (props: Props) => {
 33	  const [isKebabOpen, setIsKebabOpen] = React.useState<boolean>(false);
 34	
 35	  const onKebabToggle = (isOpen: boolean) => {
 36	    setIsKebabOpen(isOpen);
 37	  };
 38	
 39	  const namespaceActions = props.actions.map((action, i) => {
 40	    if (action.isSeparator) {
 41	      return <Divider key={`separator_${i}`} />;
 42	    }
 43	
 44	    if (action.isGroup && action.children) {
 45	      return (
 46	        <DropdownGroup
 47	          key={`group_${i}`}
 48	          label={action.title}
 49	          className={groupMenuStyle}
 50	          children={action.children.map((subaction, j) => {
 51	            const itemKey = `subaction_${i}_${j}`;
 52	
 53	            const item = (
 54	              <DropdownItem
 55	                key={itemKey}
 56	                isDisabled={subaction.isDisabled}
 57	                onClick={() => (subaction.action ? subaction.action(props.namespace) : undefined)}
 58	              >
 59	                {subaction.title}
 60	              </DropdownItem>
 61	            );
 62	
 63	            return subaction.isDisabled
 64	              ? renderDisabledDropdownOption(
 65	                  `tooltip_${itemKey}`,
 66	                  TooltipPosition.left,
 67	                  'User does not have enough permission for this action',
 68	                  item
 69	                )
 70	              : item;
 71	          })}
 72	        />
 73	      );
 74	    } else if (action.title && action.action) {
 75	      const item = (
 76	        <DropdownItem
 77	          key={`action_${i}`}
 78	          isDisabled={action.isDisabled}
 79	          data-test={action['data-test']}
 80	          onClick={() => (action.action ? action.action(props.namespace) : undefined)}
 81	        >
 82	          {action.title} {!!action.isExternal ? <ExternalLinkAltIcon /> : undefined}
 83	        </DropdownItem>
 84	      );
 85	
 86	      return action.isDisabled
 87	        ? renderDisabledDropdownOption(
 88	            `tooltip_action_${i}`,
 89	            TooltipPosition.left,
 90	            'User does not have enough permission for this action',
 91	            item
 92	          )
 93	        : item;
 94	    }
 95	
 96	    return undefined;
 97	  });
 98	
 99	  return (
100	    <Dropdown
101	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
102	        <MenuToggle
103	          ref={toggleRef}
104	          className={kebabToggleStyle}
105	          aria-label="Actions"
106	          variant="plain"
107	          onClick={() => onKebabToggle(!isKebabOpen)}
108	          isExpanded={isKebabOpen}
109	        >
110	          <KialiIcon.KebabToggle />
111	        </MenuToggle>
112	      )}
113	      isOpen={isKebabOpen}
114	      onOpenChange={(isOpen: boolean) => onKebabToggle(isOpen)}
115	      popperProps={{ position: 'right' }}
116	    >
117	      <DropdownList>{namespaceActions}</DropdownList>
118	    </Dropdown>
119	  );
120	};

