 80	          key={`action_${i}`}
 81	          isDisabled={action.isDisabled}
 82	          data-test={action['data-test']}
 83	          onClick={() => (action.action ? action.action(props.namespace) : undefined)}
 84	        >
 85	          {action.title} {!!action.isExternal ? <ExternalLinkAltIcon /> : undefined}
 86	        </DropdownItem>
 87	      );
 88	
 89	      return action.isDisabled
 90	        ? renderDisabledDropdownOption(
 91	            `tooltip_action_${i}`,
 92	            TooltipPosition.left,
 93	            'User does not have enough permission for this action',
 94	            item
 95	          )
 96	        : item;
 97	    }
 98	
 99	    return undefined;
100	  });
101	
102	  return (
103	    <Dropdown
104	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
105	        <MenuToggle
106	          ref={toggleRef}
107	          className={kebabToggleStyle}
108	          aria-label="Actions"
109	          variant="plain"
110	          onClick={() => onKebabToggle(!isKebabOpen)}
111	          isExpanded={isKebabOpen}
112	          icon={<KialiIcon.KebabToggle />}
113	        />
114	      )}
115	      isOpen={isKebabOpen}
116	      onOpenChange={(isOpen: boolean) => onKebabToggle(isOpen)}
117	      popperProps={{ position: 'right' }}
118	    >
119	      <DropdownList>{namespaceActions}</DropdownList>
120	    </Dropdown>
121	  );
122	};
